const sourceItems = $input.all();

const candidates = [];
const seen = new Set();

for (const item of sourceItems) {
  let feeds = [];
  try {
    const content = item.json?.result?.content;
    if (Array.isArray(content)) {
      for (const c of content) {
        if (c.type === 'text' && c.text) {
          const parsed = JSON.parse(c.text);
          if (Array.isArray(parsed.feeds)) feeds = parsed.feeds;
        }
      }
    }
  } catch (e) {}

  for (const feed of feeds) {
    if (feed.modelType !== 'note') continue;
    const id = feed.id;
    const token = feed.xsecToken || '';
    const title = feed.noteCard?.displayTitle || '';
    if (!id) continue;
    const key = `${id}__${token}`;
    if (seen.has(key)) continue;
    seen.add(key);
    const noteUrl = token
      ? `https://www.xiaohongshu.com/explore/${id}?xsec_token=${token}`
      : `https://www.xiaohongshu.com/explore/${id}`;
    candidates.push({
      keyword: $('关键词触发').first().json.keyword,
      id, token, title, noteUrl
    });
  }
}

if (!candidates.length) {
  return [{ json: { keyword: $('关键词触发').first().json.keyword, parseWarning: '未识别出笔记' } }];
}

return candidates.slice(0, 20).map(item => ({ json: item }));

const detailItems = $input.all();

const merged = detailItems.map((item, index) => {
  // MCP Client wraps the response in result.content[].text (a JSON string)
  let d = {};
  try {
    const content = item.json?.result?.content;
    if (Array.isArray(content)) {
      for (const c of content) {
        if (c.type === 'text' && c.text) {
          const parsed = JSON.parse(c.text);
          d = parsed.data || parsed || {};
          break;
        }
      }
    } else if (item.json?.data) {
      d = item.json.data;
    }
  } catch(e) {}

  const note = d.note || {};
  const commentList = d.comments?.list || [];

  const description = note.desc || note.title || '';

  const comments = [];
  for (const c of commentList) {
    if (c.content) comments.push(c.content);
    for (const sub of (c.subComments || [])) {
      if (sub.content) comments.push(sub.content);
    }
  }

  return {
    keyword: $('关键词触发').first().json.keyword,
    index: index + 1,
    title: note.title || '',
    description,
    comments,
  };
});

return [{
  json: {
    keyword: $('关键词触发').first().json.keyword,
    noteCount: merged.length,
    details: merged,
  }
}];

