const items = $input.all();

function extract(item) {
  const j = item.json;
  if (j && j.summary) return j;
  if (j && j.output && j.output.summary) return j.output;
  if (j && j.output && typeof j.output === 'string') {
    try { return JSON.parse(j.output); } catch(e) {}
  }
  return {};
}

// 从 summary 解析百分比，格式如 "正向45%，负向35%，中性20%"
function parsePct(summary) {
  const r = { pos: 0, neg: 0, neu: 0 };
  const pm = summary.match(/正向\s*(\d+)%/);
  const nm = summary.match(/负向\s*(\d+)%/);
  const zm = summary.match(/中性\s*(\d+)%/);
  if (pm) r.pos = parseInt(pm[1]);
  if (nm) r.neg = parseInt(nm[1]);
  if (zm) r.neu = parseInt(zm[1]);
  // 若解析不到，均分
  if (r.pos + r.neg + r.neu === 0) { r.pos = 33; r.neg = 33; r.neu = 34; }
  return r;
}

// 从关键词字符串解析词和次数，格式如 "隐蔽便携 2次" 或 "【价格贵 3次/嫌贵】"
function parseKw(str) {
  str = str.replace(/[【】]/g, '').trim();
  const m = str.match(/^(.+?)\s+(\d+)次/);
  if (m) return { kw: m[1].trim(), n: parseInt(m[2]) };
  return { kw: str, n: 1 };
}

// ASCII 进度条（20格）
function bar(pct) {
  const filled = Math.min(20, Math.round(pct / 100 * 20));
  return '`' + '█'.repeat(filled) + '░'.repeat(20 - filled) + '`';
}

// 生成关键词排行 Markdown 表格行
function kwRows(arr) {
  if (!arr || arr.length === 0) return '| - | 暂无数据 | - | - |';
  const parsed = arr.map(parseKw).sort((a, b) => b.n - a.n);
  const total = parsed.reduce((s, k) => s + k.n, 0);
  return parsed.map((k, i) => {
    const pct = total > 0 ? Math.round(k.n / total * 100) : 0;
    return '| ' + (i + 1) + ' | ' + k.kw + ' | ' + k.n + '次 | ' + bar(pct) + ' ' + pct + '% |';
  }).join('\n');
}

const desc = extract(items[0] || {});
const cmnt = extract(items[1] || {});
const keyword = $('填装备注字段内容').first().json.keyword || '';
const now = new Date().toLocaleString('zh-CN', { timeZone: 'Asia/Shanghai' });
const dateStr = new Date().toISOString().slice(0, 10);

const dp = parsePct(desc.summary || '');
const cp = parsePct(cmnt.summary || '');

const descPosTotal = (desc.positive_keywords || []).map(parseKw).reduce((s, k) => s + k.n, 0);
const descNegTotal = (desc.negative_keywords || []).map(parseKw).reduce((s, k) => s + k.n, 0);
const cmntPosTotal = (cmnt.positive_keywords || []).map(parseKw).reduce((s, k) => s + k.n, 0);
const cmntNegTotal = (cmnt.negative_keywords || []).map(parseKw).reduce((s, k) => s + k.n, 0);

const lines = [
  '# 小红书舆情分析报告',
  '',
  '| 关键词 | 分析时间 | 笔记数 |',
  '|--------|---------|--------|',
  '| **' + keyword + '** | ' + now + ' | 最多20条 |',
  '',
  '---',
  '',
  '## 一、情感比例总览',
  '',
  '### 博主发文情感',
  '',
  '> ' + (desc.summary || '暂无'),
  '',
  '| 情感 | 占比 | 可视化（20格） |',
  '|------|------|----------------|',
  '| 😊 正向 | ' + dp.pos + '% | ' + bar(dp.pos) + ' |',
  '| 😞 负向 | ' + dp.neg + '% | ' + bar(dp.neg) + ' |',
  '| 😐 中性 | ' + dp.neu + '% | ' + bar(dp.neu) + ' |',
  '',
  '### 用户评论情感',
  '',
  '> ' + (cmnt.summary || '暂无'),
  '',
  '| 情感 | 占比 | 可视化（20格） |',
  '|------|------|----------------|',
  '| 😊 正向 | ' + cp.pos + '% | ' + bar(cp.pos) + ' |',
  '| 😞 负向 | ' + cp.neg + '% | ' + bar(cp.neg) + ' |',
  '| 😐 中性 | ' + cp.neu + '% | ' + bar(cp.neu) + ' |',
  '',
  '---',
  '',
  '## 二、关键词频次排行',
  '',
  '### 博主发文 — 正向关键词（共' + descPosTotal + '次）',
  '',
  '| 排名 | 关键词 | 频次 | 占比 |',
  '|------|--------|------|------|',
  kwRows(desc.positive_keywords),
  '',
  '### 博主发文 — 负向关键词（共' + descNegTotal + '次）',
  '',
  '| 排名 | 关键词 | 频次 | 占比 |',
  '|------|--------|------|------|',
  kwRows(desc.negative_keywords),
  '',
  '### 用户评论 — 正向关键词（共' + cmntPosTotal + '次）',
  '',
  '| 排名 | 关键词 | 频次 | 占比 |',
  '|------|--------|------|------|',
  kwRows(cmnt.positive_keywords),
  '',
  '### 用户评论 — 负向关键词（共' + cmntNegTotal + '次）',
  '',
  '| 排名 | 关键词 | 频次 | 占比 |',
  '|------|--------|------|------|',
  kwRows(cmnt.negative_keywords),
  '',
  '---',
  '',
  '## 三、汇总数据',
  '',
  '| 维度 | 正向次数 | 负向次数 | 正负比 |',
  '|------|---------|---------|--------|',
  '| 博主发文 | ' + descPosTotal + '次 | ' + descNegTotal + '次 | ' + (descNegTotal > 0 ? (descPosTotal / descNegTotal).toFixed(2) : '∞') + ' |',
  '| 用户评论 | ' + cmntPosTotal + '次 | ' + cmntNegTotal + '次 | ' + (cmntNegTotal > 0 ? (cmntPosTotal / cmntNegTotal).toFixed(2) : '∞') + ' |',
];

const markdown = lines.join('\n');
const filename = keyword + '_舆情分析_' + dateStr + '.md';

return [{ json: { keyword, markdown, filename } }];
